sql:
SELECT trader_id, total_quantity, total_value, pnl
FROM position_summary
ORDER BY total_value DESC;

SELECT MAX(total_value) AS max_total_value
FROM (
    SELECT trader_id, SUM(total_value) AS total_value
    FROM position_summary
    GROUP BY trader_id
) AS TotalValueCTE;
